// Merge und Verarbeitung der gescrapten Daten
const googleTrends = $input.first()?.json || {};
const blogData = $input.all()[1]?.json || {};

// Extrahiere Themen aus Google Trends (RSS)
let topics = [];
if (googleTrends.rss && googleTrends.rss.channel && googleTrends.rss.channel.item) {
  const items = Array.isArray(googleTrends.rss.channel.item) 
    ? googleTrends.rss.channel.item 
    : [googleTrends.rss.channel.item];

  topics = items.slice(0, 3).map(item => ({
    title: item.title,
    description: item.description || '',
    source: 'google_trends'
  }));
}

// Extrahiere Blog Themen (vereinfacht)
if (blogData.body) {
  const blogTopics = blogData.body.match(/<h[1-3][^>]*>([^<]+)</g>);
  if (blogTopics) {
    topics.push(...blogTopics.slice(0, 2).map(match => ({
      title: match.replace(/<[^>]+>/g, ''),
      description: '',
      source: 'blog'
    })));
  }
}

// Fallback wenn keine Themen gefunden
if (topics.length === 0) {
  topics = [{
    title: 'Digital Transformation 2025',
    description: 'Trends und Entwicklungen im digitalen Wandel',
    source: 'fallback'
  }];
}

return topics.map((topic, index) => ({
  json: {
    id: `topic_${Date.now()}_${index}`,
    title: topic.title,
    description: topic.description,
    source: topic.source,
    timestamp: new Date().toISOString(),
    processed: false
  }
}));

// Content Formatierung und Verarbeitung
const inputData = $input.all();
const processedContent = [];

for (const item of inputData) {
  try {
    const topicData = item.json;

    // AI Agent gibt strukturierte Daten zurück
    let contentJson = topicData;

    // Fallback falls AI Agent Fehler hat
    if (!contentJson.linkedin || !contentJson.twitter) {
      console.log('Using fallback content template');
      contentJson = {
        linkedin: `Spannende Entwicklungen zum Thema: ${topicData.title || 'Digital Innovation'}. Was denkst du darüber? #Innovation #Trends #Digital`,
        twitter: `🔥 ${topicData.title || 'Digital Innovation'} - der neue Trend! #Tech #Innovation #Digital`,
        blog: `# ${topicData.title || 'Digital Innovation'}\n\n## 1. Einführung\n## 2. Aktuelle Entwicklungen\n## 3. Auswirkungen\n## 4. Prognosen\n## 5. Fazit`,
        youtube_title: `${topicData.title || 'Digital Innovation'}: Was du wissen musst!`,
        youtube_hook: `In den nächsten 15 Sekunden erfährst du alles über ${topicData.title || 'Digital Innovation'}!`
      };
    }

    // Content bereinigen und formatieren
    const cleanContent = {
      id: topicData.id || `content_${Date.now()}`,
      topic: topicData.title || 'Unbekanntes Thema',
      source: topicData.source || 'unknown',
      linkedin: (contentJson.linkedin || '').replace(/[""]/g, '"').substring(0, 1300),
      twitter: (contentJson.twitter || '').replace(/[""]/g, '"').substring(0, 280),
      blog: contentJson.blog || '',
      youtube_title: contentJson.youtube_title || '',
      youtube_hook: contentJson.youtube_hook || '',
      created_at: new Date().toISOString(),
      status: 'generated',
      hashtags: ['#Innovation', '#Trends', '#Digital']
    };

    // Hashtags hinzufügen falls nicht vorhanden
    if (!cleanContent.linkedin.includes('#')) {
      cleanContent.linkedin += ' #Innovation #Trends';
    }
    if (!cleanContent.twitter.includes('#')) {
      cleanContent.twitter += ' #Tech';
    }

    processedContent.push({ json: cleanContent });

  } catch (error) {
    console.error('Processing Error:', error);
    // Fallback Content
    processedContent.push({
      json: {
        id: `fallback_${Date.now()}`,
        topic: 'Content Generation Error',
        error: error.message,
        status: 'error',
        created_at: new Date().toISOString()
      }
    });
  }
}

return processedContent;

