// Workflow Completion Summary
const allInputs = $input.all();
const summary = {
  workflow_id: $workflow.id,
  execution_time: new Date().toISOString(),
  total_items_processed: allInputs.length,
  successful_items: allInputs.filter(item => item.json.status !== 'error').length,
  failed_items: allInputs.filter(item => item.json.status === 'error').length,
  topics_processed: allInputs.map(item => item.json.topic).join(', '),
  status: 'completed'
};

console.log('Workflow Summary:', summary);

return [{ json: summary }];
